// mm/src/store/workflowContext.js
import React, { createContext, useContext, useMemo, useState } from 'react';

const WorkflowContext = createContext(null);

export const WorkflowProvider = ({ children }) => {
  // Upload phase controls what the Upload route renders:
  // select   -> initial upload dropzone
  // ready    -> after at least one file uploaded (shows "Start AI Analysis" button)
  // metadata -> Basic Information + Organize Your Files
  const [uploadPhase, setUploadPhase] = useState('select');

  // Book details collected in metadata (upload step)
  const [bookDetails, setBookDetails] = useState({
    title: '',
    author: '',
    category: '',
    subcategory: '',
  });

  // Manuscript files in upload step
  const [manuscriptFiles, setManuscriptFiles] = useState([]);

  // Design choices
  const [design, setDesign] = useState({
    analyzed: false,
    stage: 'typography', // typography -> layout -> trim -> summary
    typography: null,
    layout: null,
    trim: null,
  });

  // Details step
  const [details, setDetails] = useState({
    // Author Information
    prefix: '',
    firstName: '',
    middleName: '',
    lastName: '',
    suffix: '',
    contributors: [],

    // Book Information
    subtitle: '',
    description: '',
    primaryLanguage: 'English',

    // Multi-select
    ageRanges: ['All Ages'], // default
    demographics: [],
    distributionChannels: [],

    // Other fields
    marketPositioning: '',
    publishingTimeline: '',
    authorExperienceLevel: '',
    seriesInformation: '',
    brandingPreferences: '',
    marketingObjectives: '',
  });

  // ✅ Order / Checkout state (new step)
  const [order, setOrder] = useState({
    packageId: 'standard', // default selection
    deliveryEmail: '',
    paymentStatus: 'unpaid', // unpaid | processing | paid | failed
    lastError: '',
  });

  // ---- helpers ----

  // Upsert (replace by id if exists; otherwise add)
  const upsertFile = (fileMeta) => {
    setManuscriptFiles((prev) => {
      const idx = prev.findIndex((f) => f.id === fileMeta.id);
      if (idx === -1) return [...prev, fileMeta];
      const next = [...prev];
      next[idx] = { ...next[idx], ...fileMeta };
      return next;
    });
  };

  const removeFile = (id) => {
    setManuscriptFiles((prev) => prev.filter((f) => f.id !== id));
  };

  // Generic toggle for multi-select arrays in details
  const toggleDetailsMulti = (field, value) => {
    setDetails((prev) => {
      const current = Array.isArray(prev[field]) ? prev[field] : [];
      const exists = current.includes(value);
      const nextArr = exists ? current.filter((v) => v !== value) : [...current, value];
      return { ...prev, [field]: nextArr };
    });
  };

  const value = useMemo(
    () => ({
      uploadPhase,
      setUploadPhase,

      bookDetails,
      setBookDetails,

      manuscriptFiles,
      setManuscriptFiles,
      addFile: upsertFile,
      removeFile,

      design,
      setDesign,

      details,
      setDetails,
      toggleDetailsMulti,

      order,
      setOrder,
    }),
    [uploadPhase, bookDetails, manuscriptFiles, design, details, order]
  );

  return <WorkflowContext.Provider value={value}>{children}</WorkflowContext.Provider>;
};

export const useWorkflow = () => {
  const ctx = useContext(WorkflowContext);
  if (!ctx) throw new Error('useWorkflow must be used inside WorkflowProvider');
  return ctx;
};
